from astropy.units.quantity_helper.converters import converters_and_unit

# Simulate what happens when Quantity.__array_ufunc__ is called
# with (1*u.m) + DuckArray(1*u.mm)
# The inputs to __array_ufunc__ would be: (Quantity(1, 'm'), DuckArray(...))
# and the function would be np.add

import dataclasses

@dataclasses.dataclass
class DuckArray(np.lib.mixins.NDArrayOperatorsMixin):
    ndarray: u.Quantity

    @property
    def unit(self):
        return self.ndarray.unit

    def __array_ufunc__(self, function, method, *inputs, **kwargs):
        inputs = [inp.ndarray if isinstance(inp, DuckArray) else inp for inp in inputs]
        for inp in inputs:
            if isinstance(inp, np.ndarray):
                result = inp.__array_ufunc__(function, method, *inputs, **kwargs)
                if result is not NotImplemented:
                    return DuckArray(result)
        return NotImplemented

q = 1 * u.m
d = DuckArray(1 * u.mm)

# This is what happens inside __array_ufunc__
converters, unit = converters_and_unit(np.add, '__call__', q, d)
print('converters:', converters)
print('unit:', unit)
"
"}

