import sys
sys.path = ['/testbed'] + [p for p in sys.path if 'astropy' not in p.lower()]

import numpy as np
import astropy.units as u

# Test basic Quantity operations still work
print('=== Basic Quantity operations ===')

# Addition
try:
    result = (1 * u.m) + (1 * u.m)
    print('Addition:', result)
except Exception as e:
    print('Addition failed:', e)

# Addition with different compatible units
try:
    result = (1 * u.m) + (100 * u.cm)
    print('Addition with different units:', result)
except Exception as e:
    print('Addition with different units failed:', e)

# Subtraction
try:
    result = (1 * u.m) - (1 * u.m)
    print('Subtraction:', result)
except Exception as e:
    print('Subtraction failed:', e)

# Multiplication
try:
    result = (1 * u.m) * (2 * u.s)
    print('Multiplication:', result)
except Exception as e:
    print('Multiplication failed:', e)

# Division
try:
    result = (1 * u.m) / (2 * u.s)
    print('Division:', result)
except Exception as e:
    print('Division failed:', e)

# Power
try:
    result = (2 * u.m) ** 2
    print('Power:', result)
except Exception as e:
    print('Power failed:', e)

# Comparison
try:
    result = (1 * u.m) > (0.5 * u.m)
    print('Comparison:', result)
except Exception as e:
    print('Comparison failed:', e)

# Comparison with different units
try:
    result = (1 * u.m) > (50 * u.cm)
    print('Comparison with different units:', result)
except Exception as e:
    print('Comparison with different units failed:', e)

# Sin
try:
    result = np.sin(0.5 * u.rad)
    print('Sin:', result)
except Exception as e:
    print('Sin failed:', e)

# Sin with degrees
try:
    result = np.sin(30 * u.deg)
    print('Sin with degrees:', result)
except Exception as e:
    print('Sin with degrees failed:', e)

print()
print('=== Operations with plain arrays ===')

# Quantity + plain array
try:
    result = (1 * u.m) + np.array([1, 2, 3])
    print('Quantity + array:', result)
except Exception as e:
    print('Quantity + array failed:', type(e).__name__, e)

# Plain array + Quantity
try:
    result = np.array([1, 2, 3]) + (1 * u.m)
    print('Array + Quantity:', result)
except Exception as e:
    print('Array + Quantity failed:', type(e).__name__, e)

print()
print('=== Operations with incompatible types ===')

# Quantity + string (should still raise error)
try:
    result = (1 * u.m) + 'hello'
    print('Quantity + string:', result)
except TypeError as e:
    print('Quantity + string raised TypeError (expected):', e)
except Exception as e:
    print('Quantity + string raised other error:', type(e).__name__, e)
"
"}

